payload.raw:
{
  "layout": "timeline",
  "title": "推广模式：灯塔验证",
  "events": [
    {
      "date": "行业深耕期 (0-12个月)",
      "title": "聚焦航空与国防，打造标杆案例",
      "description": "深度匹配中航光电、北方兵器研究所等标杆客户核心痛点，定制“硬件+虚拟场景+量化评估”方案。通过试点交付验证价值（培训周期缩短40%、耗材损耗下降90%），沉淀《航空装配实训白皮书》等标准化销售工具包，固化“需求诊断-方案验证-价值量化-案例转化”全流程SOP。"
    },
    {
      "date": "区域拓展期 (12-24个月)",
      "title": "依托生态网络，实现区域渗透",
      "title": "依托生态网络，实现区域渗透",
      "description": "依托哈工大智能人机交互研究中心等校企合作平台，将灯塔案例转化为联合品牌资产。策划产教对接会获取高质量线索，建立产教融合基地与季度沙龙机制。联合中国一重、哈电集团等共建东北区域实训示范点，以“技术展示+本地化服务”模式拓展市场。"
    },
    {
      "date": "全国复制期 (24个月后)",
      "title": "提炼标准方案，推动跨域增长",
      "description": "提炼标准化推广包，结合线上技术直播、行业白皮书精准投放。拓展至轨道交通、能源装备等新行业，通过全国性峰会实现跨域复制，构建“标杆引领-区域扎根-生态辐射”的可持续增长体系。"
    }
  ]
}

