payload.raw:
{
  "layout": "list-featured",
  "title": "团队结构与精神",
  "subtitle": "",
  "cards": [
    {
      "icon": "users",
      "heading": "扁平化架构与核心引领",
      "body": "团队构建“核心引领、模块协同”的扁平化架构，由范柳丰博士统筹战略与技术攻坚，下设技术研发、产品运营与质量供应链三大职能模块。"
    },
    {
      "icon": "cpu",
      "heading": "技术研发模块",
      "body": "专注手势识别算法优化、柔性传感器集成与多模态系统架构设计，由软件、硬件及系统架构负责人组成，实现核心技术自主攻关。"
    },
    {
      "icon": "package",
      "heading": "产品运营模块",
      "body": "深度联动用户需求与开发者生态，负责实训场景验证策划及社群运营，推动产品与市场精准对接。"
    },
    {
      "icon": "check-circle",
      "heading": "质量供应链模块",
      "body": "严守军工/医疗级可靠性标准，高效对接纳米材料等关键供应链，确保产品从研发到落地的质量闭环。"
    },
    {
      "icon": "graduation-cap",
      "heading": "哈工大人才梯队",
      "body": "7人核心团队均源自哈工大计算学部，形成“1博士+5硕士+1本科”梯队，专业覆盖计算机科学、软件工程、材料工程，实现全链条能力闭环。"
    },
    {
      "icon": "refresh-cw",
      "heading": "敏捷协同与校训精神",
      "body": "日常采用Scrum敏捷模式，通过站会与迭代评审强化跨模块协同。团队扎根哈工大“规格严格，功夫到家”校训，聚焦科技报国使命。"
    }
  ]
}

